// Solution
function validateIdMiddleware(req, res, next) {
  const id = req.params.id;
  if (id === undefined) {
    res.status(404).send('ID is missing');
  } else if (isNaN(id)) {
    res.status(404).send('Invalid ID');
  } else {
    const allowedIds = [1, 2, 3];
    if (allowedIds.includes(parseInt(id))) {
      res.send(`ID ${id} is valid`);
    } else {
      res.status(404).send('Invalid ID');
    }
  }
}

solutions.python:
class Solution {
  def validateIdMiddleware(self, req, res):
    id = req.params.id
    if id is None:
      res.status(404).send('ID is missing')
    elif not id.isdigit():
      res.status(404).send('Invalid ID')
    else:
      allowedIds = [1, 2, 3]
      if int(id) in allowedIds:
        res.send(f'ID {id} is valid')
      else:
        res.status(404).send('Invalid ID')
}
